import{_ as a,o as p,c as i,a3 as l}from"./chunks/framework.gsMzR_Kb.js";const u=JSON.parse('{"title":"文昌帝君阴骘文","description":"一篇从存心与阴德落到日用善行的劝善短文。","frontmatter":{"title":"文昌帝君阴骘文","description":"一篇从存心与阴德落到日用善行的劝善短文。","category":"guide","aliases":["阴骘文","文昌帝君阴骘文","wenchang yinzhiwen"],"source":["《文昌帝君阴骘文》"]},"headers":[],"relativePath":"daoism/daoist-classics/wenchang-yinzhiwen.md","filePath":"daoism/daoist-classics/wenchang-yinzhiwen.md","lastUpdated":1777132262000}'),o={name:"daoism/daoist-classics/wenchang-yinzhiwen.md"};function d(c,e,t,r,n,h){return p(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="文昌帝君阴骘文" tabindex="-1">文昌帝君阴骘文 <a class="header-anchor" href="#文昌帝君阴骘文" aria-label="Permalink to &quot;文昌帝君阴骘文&quot;">​</a></h1><h2 id="【原典层】原文" tabindex="-1">【原典层】原文 <a class="header-anchor" href="#【原典层】原文" aria-label="Permalink to &quot;【原典层】原文&quot;">​</a></h2><p>帝君曰：“吾一十七世为士大夫身，未尝虐民酷吏；救人之难，济人之急，悯人之孤，容人之过。广行阴骘，上格苍穹。人能如我存心，天必锡汝以福。”</p><p>于是训于人曰：“昔于公治狱，大兴驷马之门；窦氏济人，高折五枝之桂。救蚁，中状元之选；埋蛇，享宰相之荣。欲广福田，须凭心地。行时时之方便，作种种之阴功。利物利人，修善修福。正直代天行化，慈祥为国救民。存平等心，扩宽大量。忠主孝亲，敬兄信友。和睦夫妇，教训子孙，毋慢师长，毋侮圣言。</p><p>或奉真朝斗，或拜佛念经。报答四恩，广行三教。谈道义而化奸顽，讲经史而晓愚昧。济急如济涸辙之鱼，救危如救密罗之雀。矜孤恤寡，敬老怜贫，举善荐贤，饶人责己。措衣食，周道路之饥寒；施棺椁，免尸骸之暴露。造漏泽之仁园，兴启蒙之义塾。家富，提携亲戚；岁饥，赈济邻朋。</p><p>斗秤须要公平，不可轻出重入；奴仆待之宽恕，岂宜备责苛求。印造经文，创修寺院。舍药材以拯疾苦，施茶水以解渴烦。点夜灯以照人行，造河船以济人渡。或买物而放生，或持斋而戒杀。举步常看虫蚁，禁火莫烧山林。</p><p>勿登山而网禽鸟，勿临水而毒鱼虾。勿宰耕牛，勿弃字纸。勿谋人之财产；勿妒人之技能；勿淫人之妻女；勿唆人之争讼；勿坏人之名利；勿破人之婚姻。勿因私仇，使人兄弟不和；勿因小利，使人父子不睦。勿倚权势而辱善良，勿恃富豪而欺穷困。</p><p>依本分而致谦恭，守规矩而遵法度。谐和宗族，解释冤怨。善人则亲近之，助德行于身心；恶人则远避之，杜灾殃于眉睫。常须隐恶扬善，不可口是心非。恒记有益之语，罔谈非礼之言。翦碍道之荆榛，除当途之瓦石。修数百年崎岖之路，造千万人来往之桥。垂训以格人非，捐赀以成人美。作事须循天理，出言要顺人心。见先哲于羹墙，慎独知于衾影。</p><p>诸恶莫作，众善奉行。永无恶曜加临，常有吉神拥护。近报则在自己，远报则在儿孙。百福骈臻，千祥云集，岂不从阴骘中得来者哉？”</p><p><img src="https://www.fridolph.top/static/dao/yinzhiwen.png-minwebp.webp" alt="文昌帝君阴骘文"></p><h2 id="【原典层】当前共学原文-节选" tabindex="-1">【原典层】当前共学原文（节选） <a class="header-anchor" href="#【原典层】当前共学原文-节选" aria-label="Permalink to &quot;【原典层】当前共学原文（节选）&quot;">​</a></h2><p>帝君曰：“吾一十七世为士大夫身，未尝虐民酷吏；救人之难，济人之急，悯人之孤，容人之过。广行阴骘，上格苍穹。人能如我存心，天必锡汝以福。”</p><h2 id="【原典层】注音-生僻字" tabindex="-1">【原典层】注音 / 生僻字 <a class="header-anchor" href="#【原典层】注音-生僻字" aria-label="Permalink to &quot;【原典层】注音 / 生僻字&quot;">​</a></h2><ul><li>骘：<code>zhì</code></li><li>锡：<code>xī</code></li></ul><h2 id="【原典层】当前读到" tabindex="-1">【原典层】当前读到 <a class="header-anchor" href="#【原典层】当前读到" aria-label="Permalink to &quot;【原典层】当前读到&quot;">​</a></h2><ol><li><code>吾一十七世为士大夫身……容人之过</code></li><li><code>广行阴骘，上格苍穹。人能如我存心，天必锡汝以福。</code></li><li><code>于是训于人曰：昔于公治狱，大兴驷马之门；窦氏济人，高折五枝之桂。</code></li><li><code>欲广福田，须凭心地。</code></li><li><code>行时时之方便，作种种之阴功。</code></li><li><code>利物利人，修善修福。</code></li><li><code>正直代天行化，慈祥为国救民。</code></li><li><code>存平等心，扩宽大量。</code></li><li><code>忠主孝亲，敬兄信友。</code></li><li><code>和睦夫妇，教训子孙，毋慢师长，毋侮圣言。</code></li><li><code>或奉真朝斗，或拜佛念经。</code></li><li><code>报答四恩，广行三教。</code></li><li><code>谈道义而化奸顽，讲经史而晓愚昧。</code></li><li><code>济急如济涸辙之鱼，救危如救密罗之雀。</code></li><li><code>矜孤恤寡，敬老怜贫。</code></li></ol><h2 id="【原典层】典故速记" tabindex="-1">【原典层】典故速记 <a class="header-anchor" href="#【原典层】典故速记" aria-label="Permalink to &quot;【原典层】典故速记&quot;">​</a></h2><ul><li>于公治狱：于公长期治狱，重在持平、不冤人。后来其家门庭显达，故有“驷马高门”之说。放在这里，不是在讲富贵本身，而是在说：即便做的是审狱断案这种严厉之事，只要不枉人、不偏私，也是在积德。</li><li>窦氏济人：窦氏常被理解为窦禹钧。传说他修德济人，后来五子皆有成就，故有“五枝桂”之喻。放在这里，是在说：济人之善并非空言，长久去做，会慢慢在家门与后人身上显出回响。</li></ul><h2 id="【解读层】开篇导读" tabindex="-1">【解读层】开篇导读 <a class="header-anchor" href="#【解读层】开篇导读" aria-label="Permalink to &quot;【解读层】开篇导读&quot;">​</a></h2><p>《文昌帝君阴骘文》和《太上感应篇》气质相近，都落在善行与劝善上，但它的起手方式不太一样。它不是先列出一大串戒条，而是先拿“自己如何存心、如何做人”来立一个样子，再慢慢把善行从这里展开。</p><p>当前读到这里，最先显出来的有三条线：</p><ul><li>时间积累后的厚重感</li><li><code>容人之过</code> 的难</li><li><code>阴骘</code> 与 <code>存心</code> 并不在热闹处，而更在无人处、细小处</li><li>善不只长成“帮人”的样子，也会长成“守公道、守职责”的样子</li></ul><h2 id="【解读层】我的理解-当前阶段" tabindex="-1">【解读层】我的理解（当前阶段） <a class="header-anchor" href="#【解读层】我的理解-当前阶段" aria-label="Permalink to &quot;【解读层】我的理解（当前阶段）&quot;">​</a></h2><p>读到“一十七世为士大夫身”时，我最先感到的是一种很厚的时间感。不是一时做了几件好事，而像是很长很长的时间里，都在守着差不多的做人方向。这样一来，后面的“救人之难，济人之急，悯人之孤，容人之过”也就不只是几句漂亮的话，而像是经过很多世、很多事之后，仍然没有丢掉的东西。</p><p>这里最打动我的，其实是“容人之过”。前面几句，我们本能上会觉得都是明显的好事，可“容人之过”却难得多。因为这不是单纯帮助一个处境可怜的人，而是在明知道对方有不妥、有过失时，仍然不急着把人定死，还能留一点余地和宽厚。我会觉得，这比单纯地帮人更难。</p><p>再读“广行阴骘，上格苍穹。人能如我存心，天必锡汝以福”时，我最先抓到的是“阴骘”和“存心”。阴骘对我来说，不一定是什么很大的词，反而更像无人处的一点真心，一点不求回报的小善。比如不浪费，不乱扔垃圾，不随意伤物，没人看见时也还是愿意这样做。事情虽然小，却很能照见一个人是不是顺着本心在活。</p><p>而“存心”这两个字，我现在不太想把它理解成一个很用力的动作。若总提醒自己“我要存一颗善心”，心反而容易紧起来。倒不如慢慢把心放平一点。功利、比较、想被看见、做久了没人回应时的失落，这些都会来，也不丢人。只是当这些声音都来了以后，自己还能不能分清：现在到底是本心想做，还是被外面的声音推着做。若一件事即便没人知道、没人表扬，也还是愿意去做，那也许就更接近这里说的“存心”了。</p><p>我现在会觉得，天赐不赐福当然很好，但也未必是最重要的。人也许一开始会因求福而行善，可若做久了，哪怕没有立刻得福，也还是愿意继续去做，那这颗心才算慢慢安住了。</p><p>再往后读“昔于公治狱，大兴驷马之门；窦氏济人，高折五枝之桂”，我会觉得这两个例子放在一起很有意思。表面看，一个是在治狱断案，一个是在直接济人，好像完全不是一类事。但细想又有相通的地方：于公的不冤枉人，是在护人、护公道，只是这种善不一定长得温柔显眼；窦氏济人则是明面上更容易被看见、也更容易被称赞的善。</p><p>所以这两则典故像是在提醒我：善不一定都长成“帮人”的样子，有时也长成“守公道、守职责、守本分”的样子。若只盯着哪一种善更容易被夸，心就容易偏到求福那边去了。可若能在不显处、在职责里、在无人称赞时，仍然愿意把事情做正、把人护住，那也许更接近这里说的阴骘与存心。</p><p>再往深一点想，我也会隐隐觉得，路上真正危险的，也许未必只是难，而是心慢慢偏了却不自知。比如原本只是想安静地学、认真地走，可走着走着，也可能会冒出“我是不是也该证明点什么”“别人会怎么看我”“这样做有没有回响”这些念头。它们不一定多坏，可若不知不觉把心交给了这些外面的声音，那把利刃就像一直悬在那里。</p><p>所以现在对我来说，“写下来”也变得很重要。不是为了把自己写得多明白，而是文字有时真能照见自己。写的时候，我会更清楚地看到：我现在到底是在顺着本心说，还是已经有些偏了；我此刻到底是清醒的，还是只是被情绪、被外面的东西推着走。也许几年以后再回头看，同样的文字会有不同的理解，但至少这一刻的真心被留住了。到头来，我在意的也不是当下说得有多漂亮，而是以后回看时，初心还在不在，我还能不能像现在这样，对自己的内心保持一点诚实。</p><p>再往下想，我会觉得，偏没偏，其实自己往往是知道的。不是一定要等别人提醒，不是一定要出什么大问题，很多时候心里会先有一种感觉：字开始硬了，心开始急了，眼里只剩结果了，或者反过来，自我感觉太好了，觉得已经不用再照看自己了。真到那一步，往往就已经有些失准了。所以我现在更愿意把“存心”理解成一种平常的自省，不必弄得很紧张，却也不能完全放任。每日三省也好，偶尔停下来照一照自己也好，都是在尽量不让那颗心走远。不是为了把自己修成什么样子，只是希望还能一直认得出，什么是自己真正想走的路。</p><p>读到“欲广福田，须凭心地”时，我会先想到“土壤”这个感觉。福田不是做样子做出来的，心若薄、若硬、若只想着收成，再怎么忙，也未必真能长出什么；可若心地慢慢养厚了，很多善也就不是硬做出来的，而是会自然生出来。所以“心地善良”这句平常话，到这里忽然就变得很实，不再只是夸人，而像是在说：这个人里面那块地，还能长东西。</p><p>我现在也越来越觉得，“心地”不是没见过现实，更不是天真到什么都信。恰恰相反，有时是看多了真假难辨、看多了人的苦和人的假，心会先慢慢收紧。以前我也有过那样的时候，看到路边求助的人，会先怀疑，会先退一步，觉得自己没必要卷进去。可后来又有几次，碰到流浪歌手，碰到说家里有人病重、在路边卖艺求援的人，我还是会顺手捐一点，不多，<code>1</code> 块、<code>2</code> 块、<code>5</code> 块，全凭心意。说实话，我也不知道最后是真是假，可至少那一刻，看见别人的苦难是真，我心里那一下不忍也是真。</p><p>有一次我其实犹豫了很久，红绿灯快结束了，我本来都准备走了。可就在那时，我看到一位阿姨很真诚地说了几句祝愿，又握了握对方的手，把钱递过去。那位求助的人低下头，很虔诚地说感谢。看到这一幕，我也慢慢扫了两块钱过去，然后赶着绿灯走了。其实我连对方后面的反应都没再看清，可那一刻心里反而落下了。现在回头想，也许我在做的，不只是帮别人，更像是在替自己守住一点东西。不是非要分辨对方到底是真难还是假难，不是每一次都要把真假彻底审清才允许自己动心。有时全凭心地，觉得难，觉得应当，那就给一点；觉得不对，觉得没必要，那就走开。别计较得太过，别把心也磨得太硬，这对我来说，也是一种很小却很真的修。</p><p>再读“行时时之方便，作种种之阴功”，我会先把“方便”理解得很日常。不是非要等什么大机会，也不是一定要做出多大的事，而是在当下碰到的每一件小事里，能顺手帮一点，就帮一点。比如坐电梯时，多等那几秒，看看后面还有没有人要上来；比如出小区门时，帮后面的人扶一下门；比如遇见保安大叔，不只是擦肩而过，而是回一句“早上好”“晚上好”“辛苦了”。这些事情看起来都很小，小到平时甚至不觉得自己在“行善”，可我现在反而觉得，正因为它们小，才最接近日用，也最能看出一个人心是不是还活着、是不是还愿意对世界多放出一点温度。</p><p>这样看，“方便”就不只是帮助别人，也是把自己活得别那么硬。不是为了积什么功，不是为了被谁看见，而是在一件件顺手可做的小事里，让心不要只顾自己，不要越来越紧。若能一直这样做下去，那些不显眼的小动作，也许才真是“种种阴功”最自然的样子。</p><p>再顺着“作种种之阴功”往里想，我现在会觉得，重点其实还是落在“功”上。“阴”更像它的方式: 不张扬，不求人知，不一定非要被谁看见、被谁记住。可真正会留下来的，不只是做过多少件事，而是这些事情慢慢把人磨成了什么样子。对我来说，这一层反而比“积少成多”更有感觉。因为若只是记着自己做了多少，心还是容易着相；可若做着做着，气质慢慢和缓了，人也没那么硬了，开始愿意对陌生人露出一点微笑，愿意把善意自然地放出来，那才像是真的有东西在身上发生了。</p><p>若这样看，“阴功”也不只是藏起来的功，而像是一种不喧哗的生长。别人未必知道，自己也未必时时数得清，可它会一点一点改变一个人的神色、说话、待人接物的方式。到那时，善就不再只是“我做过一些好事”，而更像“我正在慢慢变成一个愿意把温度给出去的人”。</p><p>我后来也慢慢发现，这种变化很多时候不是一下子“想通”的，而是被生活里真实的人带出来的。比如我楼下以前有位保安大叔，人很好，会主动给人开门，也会先说“早上好”。后来他调岗还是离职了，换了新的师傅。因为对方不主动，我也就继续沉默着，住了那么多年，彼此几乎都没怎么对上眼。直到有一次，我看到伴侣很自然地先跟师傅打招呼，师傅也立刻友善起来，帮忙开门，回应得很真诚。那一下我像是被轻轻点了一下，后来也开始学着主动说一句谢谢、说一句早上好。慢慢地，彼此就熟了。</p><p>现在回头看，我在这里住了快七年，反而是最近两年，才开始有这样一点细小却真实的变化。它看起来并不宏大，可我会觉得，这种“愿意先开口、愿意先露出一点善意”的变化，本身就很珍贵。因为它说明，所谓“阴功”未必只是做了多少件事，也可能是人在与人的日常往来里，被一点一点养得更有温度了。</p><p>若再往里说一点，我会觉得自己少掉的，更多还是防备。以前人与人之间，心里总像隔着一层，不一定是把谁看得很坏，只是先习惯了不靠近、先习惯了彼此设防。可这两年慢慢有些不同了，像是自己身上那层遮蔽薄了一点，也更愿意承认：很多时候，对面未必真有恶意，很多关系也不是非要等别人先来，自己才敢回应。</p><p>这样一想，我反而会觉得，与人相遇本身就是一件很妙的事。有时两个人都在等，都在看，都在防着一点，那连接就停在那里了。可若其中一方先迈出半步，事情就可能完全不同。以前先迈步的人常常是别人，现在我也愿意试着做那个先开口的人，先点头，先问候，先露出一点善意。不是因为自己忽然变得多热情，而是觉得，若对方并不坏，那与其互相设防，不如让我先把这一步走出来。到这里，我会觉得“阴功”已经不只是在说做了什么，而是在说一个人是不是慢慢愿意把自己从防备里松开，去跟这个世界重新连上。</p><p>再读到“利物利人，修善修福”，我会觉得善和福其实本就是一体两面的。只是人活在当下，常常还是需要一个先后的次第，才比较看得清。于是会先说“善在前，福在后”，好像是先修善，再得福。这样的说法没有错，也更容易让人明白。可若再往里想一点，也许很多时候，福并不是后来才忽然来的，而是善早就在一些自己没留意的地方发生了，只是当时没有看见，所以等福先落到身上时，才会恍然觉得它像是提前到了。</p><p>这样一来，我反而不太想把“修善修福”读成交易。不是我先付出一点善，然后再去换一点福；而更像是，一个人顺着本心慢慢把善修出来时，福也已经在其中一起长着了。只是“善”更像是自己能把握、能看见、能立刻去做的那一面；“福”则更像回响，有时来得慢一点，有时早已来到，只是自己后来才懂。所以在我这里，善还是在前面，因为那是人能做的部分；但福也未必总在后面，因为很多好东西，也许早就在自己没注意的地方，悄悄发生了。</p><p>再读“正直代天行化，慈祥为国救民”，我最先被“慈祥”抓住。因为前面一路读下来，天地、福田、苍穹、代天行化，这些话都很大，大到人站在里面时，会先觉得自己太小，不知道自己到底能做什么。可“慈祥”一出来，气忽然就落下来了一点，人也像被轻轻拉回地上。虽然“为国救民”听起来还是很大，可至少这里先有了一种贴近人的感觉。</p><p>我现在理解的“慈祥”，更像温柔、善良、真诚。不是软弱，也不是故意摆出和气的样子，而是一种待人时身上自然带出来的暖意。若再深一点，它也像是见过一些事之后，心没有因此彻底变硬，仍然愿意善待别人。这样去读，我会觉得这句并不是在逼人一上来就担起多大的责任，而像是在说：若真想走到更大的地方，先要让自己这个人身上有一点慈祥。因为很多大的承担，最后也还是要落在一个人怎么说话、怎么待人、怎么不轻易伤人上面。</p><p>若再回头看前面的“正直”，我现在反而不太想先把它读成品德标签里的“正直”。在《阴骘文》这里，它更像是一种状态：站得正，于是自然直；不是先给自己贴一个“我是正直的人”的名字，而是人在事上、在现实里，不那么容易被带歪。这样理解，我会觉得它和“慈祥”正好一硬一柔。慈祥让人不至于冷，不至于伤；正直则让人不至于飘，不至于歪。</p><p>这一层我会不自觉想到“立干”。一棵树能不能站住，不只是看枝叶漂不漂亮，而是看干正不正、根稳不稳。人也差不多。现实里有人情，有利害，有各种会把人带偏的东西，若里面没有一根自己真认的“干”，就很容易顺着风走。至于这根“干”到底叫善、叫诚、叫信、叫忠，或者别的什么，也未必要一口气都说尽。对我来说，也许不必把所有好的词都囊括，只要先守住自己真正认的、经得起推敲的那一根，就已经很不容易了。若那根在，人就算有摇摆，也不至于整个人都歪掉。</p><p>若再往根上追一点，我现在会觉得，自己最想守住的，也许还不是某一个单独的德目，而是一种更本质的东西: 本然信任。不是轻信，不是没有判断地把一切都交出去，而是心里仍愿意承认，这个世界并不只由恶意和算计构成，人和人之间也不是只能互相提防。对我来说，正因为还有这样一点本然的信任在，后面的很多东西才慢慢长得出来。善意会从这里生，怜悯会从这里生，同理心会从这里生，看待世界的方式也会慢慢跟着变。</p><p>这样一来，“正直”对我就不只是守某个规矩，而像是在守这根更深的东西。因为若连本然的信任都失了，人就很容易只剩防备，只剩评判，只剩先把自己保护起来。可若这根还在，哪怕自己也见过很多复杂、很多灰暗，心里还是会有一点余地，愿意去理解，愿意去靠近，愿意先放出一点善。这种感觉，也让我觉得《阴骘文》前面那些“方便”“阴功”“慈祥”，其实都不是散开的，它们背后像有一条暗线，最后都能回到这根更深的本心上来。</p><p>再读到“存平等心，扩宽大量”，我会觉得这句像是在写一个人胸怀打开的过程。前面说“正直”“慈祥”，像是在讲人的骨与温；到这里，话又往里面收了一层，开始讲一个人的心是不是太只站在自己这边。对我来说，这里的“平等心”并不只是抽象地讲人人平等，而更像是在提醒自己：别总急着从“我”的感受、“我”的立场、“我”的委屈出发。不是不要自己，而是别每次都只剩自己。</p><p>若这样去读，后面的“扩宽大量”也就顺了。起初我也觉得这个说法有些生，可慢慢又会想到那句老话：“宰相肚里能撑船。”不是说人真要大到什么地步，而是至少别让自己的心里太挤，别只能装下自己那点判断、情绪和输赢。若心里还能多容下几个人，多容下一些不同，多容下一些不顺自己意的事，那这里说的“宽大量”也许就出来了。这样一来，这句不是两件分开的事，而更像一个次第：心先放平，量才慢慢放大。若总只站自己这边，量其实很难大；可若心里先松半步，愿意去看别人那一侧，胸怀也就开始不一样了。</p><p>这种变化，我现在最能在和伴侣相处时感觉到。以前我们经常因大小事争吵，虽然很多时候很快又会过去，但情绪上来的时候，话总容易顶上去，听起来也容易盛气凌人，像自己站在更高的位置说话。现在我会尽量提前感知到一些问题，能规避就先规避，规避不了时，也会先从体谅和同理的角度去描述，让话别那么硬、别那么高高在上。大的争执反而少了。工作里也差不多。和后端、测试同事配合时，若能先站到他们的角度想一点，再把很多无谓的是非输赢放淡一些，最后往往不是效率更低，反而更顺了。到这里我会觉得，“平等心”不只是讲态度，而是让自己别总站到上面去；心一平，很多不必要的争，就先下来了。</p><p>再读“忠主孝亲，敬兄信友”，我也不太想先把它只当作旧时代的伦理口号。它当然很传统，带着很强的关系次序，可我现在反而会觉得，现代人的迷茫，很多也恰恰来自于这些关系都慢慢松掉了，最后看似更自由，心里却越来越没有着落。这里把不同关系并列摆出来，像是在提醒人：对外有应尽之责，对内有不该忘的根；对年长者有敬，对平辈朋友有信。它不一定是在说现实中永远不会有冲突，而更像是在先立一个方向，让人别彻底把这些关系都活散了。</p><p>而在这一句里，我自己最有感觉的，还是“信”。但这个“信”对我来说，又不太像“我要做一个让别人信服的人”。若还是先想着外面的认可，那根其实还在别人那里。现在我更偏向从内里去读它：先不辜负自己，先想明白自己到底认什么、守什么、想做什么样的事。因为若连自己心里认定的东西都守不住，再谈让别人相信，也很容易变成一种表演。反过来，若一个人真的先对得起自己心里认的那条路，外面的信任反而会慢慢长出来。不是去争来的，而是别人会渐渐感觉到：这个人说的话、做的事、走的方向，是对得上的。</p><p>再读“和睦夫妇，教训子孙，毋慢师长，毋侮圣言”时，我会觉得这一句讲的，其实是一条很完整的人伦次序与心性次序。先是“和睦夫妇”，让我想到关系里最重要的，也许不是谁压谁、谁定死做什么，而是两个人能不能把日子过出和气、体谅与亲近。所谓“和”，是先不相冲，能相处；所谓“睦”，则更进一步，是相处久了以后，里面慢慢生出亲、理解与愿意彼此靠近的心。接着是“教训子孙”，其中“教”更像引导、示范、慢慢带着长，“训”则像提醒、规正、立边界、止偏差。起初我会把“子孙”理解成血缘上的后代，但再往下想，它也可以指比自己更后面的人，指那些会被自己影响、承接自己所作所为的人。这样，这一句就不只是家庭里的教养问题，而是在说：一个人要不要把自己认定的东西、活出来的分寸，继续往下传。再读“毋慢师长”，我最有感的是“慢”字。难的不只是表面的失礼，而是心里的轻慢。学了一点、懂了一点之后，最容易觉得别人不如自己，尤其面对长辈、前辈、老师时，这种轻慢更细，也更难察觉。可一旦心里先轻了，耳朵其实就关上了，后面哪怕真有一句从生活里熬出来的话，也很难再听进去。最后的“毋侮圣言”，则比“慢”更重一层。它提醒我的，不是盲从，而是敬重。所谓“圣言”，既可以是圣贤留下来的话，也可以是那些更接近大道、并且经得起人反复体会的话。若还没真正读进去、想明白，就先轻薄它、裁断它、顺着自己的意思去曲解它，这便已经有了“侮”的味道。合起来看，这一句不只是劝人守礼，更像是在说：对最亲近的关系，要活出和睦；对更后面的人，要愿意传递；对走在前面的人，要保持谦卑；对真正有分量的话，要存一份敬意。</p><p>再读“或奉真朝斗，或拜佛念经”时，我最先感到的，不是哪一路更高，而是它根本没有急着分高下。“或……或……”像是在先把门户之争放下来，承认人有不同的根器、经历与入口，所以走法也未必一样。有人更贴近“奉真朝斗”这一类向内守真、向上知天的路，有人则从“拜佛念经”这样更具体、更熟悉的修持方式进入。对我来说，“真”很难一下说死，真心、真理、真性、不自欺，甚至一切最后能归到本然处的东西，好像都可以往那里靠。正因为“真”太大，所以这里更重要的反而是“奉”字：不是去占有，不是去定义，也不是拿来压人，而是一种愿意去守、去持、去贴近的姿态。至于“朝斗”，原本当然有郑重的礼仪意味，可若只把它读成外在仪式，又会离日常太远。对我来说，它也可以先是一种很简单的姿态：愿意抬头看天，愿意承认自己并不是一切的中心，愿意把心从眼前那点得失里稍微提起来一点。这样，“奉真”是向内守真，不自欺；“朝斗”则像向上知天，不自满。合起来看，这一句不像在分宗派，而是在提醒：路可以不同，形式可以不同，但都不必急着争谁更正、谁更高，关键还是那颗心在不在，自己是不是在认真地奉、认真地持、认真地把心收回来。</p><p>再读“报答四恩，广行三教”时，我会觉得，这一句开始把人从个人修持里再往外推了一层。所谓“报答”，也有自己的次第：先“报”，是记得自己承过什么、受过什么，没有忘；再“答”，是拿行动慢慢回过去，不让这份恩只停在嘴上。所以真正的报答，未必总是原样回给原来那个人，也可能是因为自己受过恩，便愿意把这份好继续往下传。至于“四恩”，我不会急着把它扣死成某一份固定名单。对我来说，它更像是在提醒：人并不是凭空活着的。天地的承载、父母的养育、师长的教诲、他人的扶持，乃至许多自己未必时时觉察的成全，都在托着一个人慢慢走到今天。能记得，才谈得上报；愿意回过去，才谈得上答。而“三教”放在这里，我更倾向于先按儒、释、道来读，可这句真正可贵的，又不是替哪一家争高下，而是“广行”二字。比起“三教”具体指什么，我反而更会被“广行”这两个字抓住。因为它一下把重点从“知道什么”拉回到了“活出什么”。“广”不只是传播得广，更先是心量要广；心若不广，传播也容易变味，容易变成争门户、争解释权。可若一个人心里真能容得下不同入口、不同门路，也容得下别人理解得慢、走得慢，那么他自然会希望好的东西传得更广。这样再看这句，它像是在提醒我：修，不只为自己清净，也该记得回报所承之恩；学，不只守一门之见，也不必争门户高下，关键还是把真正好的东西活出来，也愿意让它继续流出去。</p><p>再读“谈道义而化奸顽，讲经史而晓愚昧”时，我会觉得这句比表面看起来更有分寸。前半句里，我最先抓到的是“化”字。对我来说，化最根本的就是变化。感化也好，转化也好，教化也好，底下都还是这个“变”字。只是这里的变化，不是靠外力硬扳，也不是单纯压服，而是人里面某个地方开始松动了，开始转向了，开始不一样了。所以“谈道义而化奸顽”也就不是在讲空道理，更不是站在高处去训人，而是在说：若道义真的进去了，它是能让人变的。这里不用“惩”不用“治”，而用“化”，我会觉得很有分量，因为它像是在承认，人虽有偏、有硬、有顽的一面，却也并不是完全不能动、不能改、不能转回来。再看“奸顽”，我起初也会先往“坏”上落，尤其“奸”字，本就带着更重一点的意味。可若细分，“奸”更像心术偏了，顺着私欲、机巧、明知不正而去；“顽”则更像心硬了，不肯转，不肯听，不肯回头。这样一来，它说的就不只是坏人，而更像人在某些时候会落进去的两种状态：一种是偏，一种是硬。也正因如此，后面的“化”才显得更难，也更有分量。至于“谈道义”，第一层当然还是讲道理、讲义理，可这里最妙的反而是“谈”字。它没有写训，也没有写压，而是写谈。这样一来，道义就不只是站在高处的说教，而更像放在人与人的言谈、往来、劝说之中，慢慢讲，慢慢熏，慢慢让人听进去。对我来说，“道”偏向根本、方向与所循之路；“义”则更偏做人做事的分寸、应然与站位。若两者合起来，就不只是知道一些正确的话，而是在与人相处时，能不能把这些更正、更稳的东西，用人能听进去的方式说出来。后半句里的“晓”则正好和“化”成一组。“化”更像人在状态上慢慢变了，偏掉、硬掉的地方开始松动；“晓”则更像眼前亮了，原本蒙着、暗着、不明白的地方，慢慢透出了光。所以“讲经史而晓愚昧”也不是在堆知识、摆学问，而是在说：经与史若真讲得好，是能让人明白的。这里的“愚昧”，我更愿意把它理解成一种蒙蔽，而不只是单纯的无知。因为若只说无知，容易让人站到高处去看别人；可若是蒙蔽，味道就不同了。它像是在说，一个人并不是天生就坏、就低、就不行，而是眼前被什么遮住了，心里有些地方还没亮起来。这样再看这句，它就不只是劝人读书、讲理，而是在提醒：对偏而硬的人，要相信他仍有可化之处；对蒙而昧的人，也要愿意用更有光的东西去照他一点。读到这里，我也会很自然地想到，许多后来长出来的理解，其实都不是凭空冒出的。我们的 Dao 也是后来者，能一点点走到今天，也是在承着前辈们留下的恩与光，只是换了一种更贴近当下的说法，再慢慢往前接而已。</p><p>再读“济急如济涸辙之鱼，救危如救密罗之雀”时，我最先被“急”与“危”抓住。急，是当下逼到眼前，拖不得；危，则是已经悬在边上，再晚一点可能就掉下去了。这样一来，这句就不只是泛泛地说帮助别人，而是在提醒：真正可贵的，不只是平时愿意做好事，而是在别人最来不及、最无助、最悬的时候，你能不能看见，也能不能及时伸手。对我来说，“济”更像帮人渡过，而不是单向施舍。就像“涸辙之鱼”，差的不是很多很多，而是那一点恰好能接上的水；这点水不是让它苟延残喘，而是让它借着这一点承接，重新有机会往下游、往活路去。至于“密罗之雀”，则更像已经落网的处境。网一密，雀越挣，往往只会越紧，到这一步，靠它自己已经很难了，所以这里不用“济”而更用“救”。这样再看整句，就不只是说善心，而是在说帮助也有分寸：有时是扶人渡过，有时则是先把人从险处解出来。</p><p>再读“矜孤恤寡，敬老怜贫”时，我会先被“矜、恤、怜”这几个字抓住。它们看起来都带着柔软之意，可若都只读成“同情”，味道就太平了。这里像是在很细地分：见人之苦时，心先如何动；动了以后，又该如何去顾、去待、去扶。对我来说，“矜”不像高高在上的怜悯，也不像一下子外放得很重的情绪，它更像是看见别人处在一种可伤、可悯、无人依靠的处境里，自己心里先轻轻收了一下，柔了一下。放在“矜孤”里，这个味道就更明显了。“孤”不只是苦，也不只是穷，它更像一种无所依、少所靠、在人世关系里偏冷偏单的状态。所以“矜孤”首先不是说我要立刻做多大的事，而是看见这样的处境时，心会不会真的被触一下，会不会对这份孤生出一种顾惜与不忍。读到“孤”时，我第一感觉还是会先落在现实处境上：失去依靠的人，少人照应的人，在人世关系里偏单偏冷的人。这一层最直，也最稳。但若再往里一点，我又会觉得，真正难的其实不是看见这种表面的孤，而是能不能察觉到那些不那么显眼的孤：一个人也许并不贫困，也并不真的独居，可心里仍很孤，在人群里也像无所依。若能连这种孤都慢慢看见，那“矜”也就不只是对一个身份起反应，而是真正对人的处境有了感。</p><p>至于“恤”，我会觉得它比“矜”又往前走了一步。若说“矜”更像看见别人的孤苦时，心里先轻轻收了一下、柔了一下，那么“恤”就不只停在心软，而更像体察、顾念、周全与照应。它里面当然也有同理心，但不只是懂其难、怜其苦，而是愿意再往前迈一点，替对方想到一点，顾到一点，甚至在需要时帮她撑一撑。这样再看“恤寡”，味道就不只是同情，而是在说：对于那些长期处在缺处、薄处、失了依凭的人，能不能不只看见她难，还愿不愿意多顾她一点。读到“寡”时，我第一反应还是会先想到“寡妇”这一层，这很自然，也不偏。可若放在“矜孤恤寡”里再细看，它又不只是一个身份名称，而更像是在写一种长期单薄、失了依凭的处境。若说“孤”更偏无所依、少所靠，那么“寡”就更带着一种家内失所恃、生活少了支柱的意味。它不一定喧哗，却往往很长，很沉，也很难独自撑住。这样再看“恤寡”，就不只是对某个身份起怜意，而是在提醒：对于这种长期处在缺处、薄处、失衡处的人，能不能多顾一点，多体察一点，不让她在日子里独自硬扛。</p><p>再读“敬老怜贫”时，我会觉得这两个字眼里的心，又和前面的“矜”“恤”略有不同。对“敬老”而言，我当然也会先想到尊重，但若只停在“因为对方年老所以要礼敬”，味道又容易太板。对我来说，更有感的反而是：不要因为一个人老了，就轻慢他。人一老，动作慢了，反应慢了，说话重复了，很多现实里的轻慢其实正是从这里生出来的。不是非要明着不敬，而是语气变了，耐心少了，眼神里也开始带着嫌烦。这样再看“敬老”，它就不只是礼貌，而是在提醒：面对已经走过长年月的人，不要只看他现在慢了、弱了、退了，也要记得他曾经站着、撑着、走着、扛着。至于“怜贫”，我最先被“怜”字抓住。因为我一直不太喜欢那句“可怜之人必有可恨之处”。人都已经落在苦处了，却还要先被评断、先被补上一刀，那种心太硬了。对我来说，这里的“怜”不是替人开脱，也不是取消因果，而是在看见一个人已经落进难处时，心里先不要急着责怪、急着论断。至于“贫”，我也不太想把它只读成经济上的穷，而更像一种整体上的窘迫：日子被卡住了，生活被压缩了，很多东西展开不开来。可即便如此，贫也不等于低一等。有些人虽然贫，精神却很富足，心气也很正，甚至让人觉得可敬。这样再看“怜贫”，就不是高高在上的同情，而是在看见一个人长期被匮乏围住时，仍愿意对他的难生出一点不忍，也仍看得见他里面的尊严。</p><p>读到“举善荐贤”时，我总会想起高中班上的一个女孩。她成绩不是最顶尖的，可我一直记得她一个很小的习惯：见到老师，总会认真地低头说一句“老师好”。这件事小到几乎不值一提，可也正因为小，才更见真。明明课本里天天写着“尊师重道”，课堂上也说得头头是道，可真有人把这种东西活出来时，大家却未必觉得那是好，反而会觉得她有点过，有点异类，甚至不太合群。我那时心里其实是佩服她的，也知道她身上那种礼貌和认真，不是表演出来的。可我也没有主动走近，因为我也怕，怕自己若靠近了，也被一起看成那种“不合群”的人。现在再回头看，我会觉得那时候的自己其实也没有多勇敢。善在那里，我看见了，也认出来了，可我没有真的站到它那边。</p><p>后来班里有过一次类似模范的匿名评选，我投了她，但她的票并不高。那时我心里其实就有不平，只是说不清。现在慢慢能说清一点了：原来人群很多时候不是认不出善，而是不愿意把真正的善举出来。大家更愿意把那些显眼的、容易量化的、能带来体面的东西推到前面，却未必愿意承认那种安静、认真、知行合一的好。再后来，很多年以后，我在老家又见到她。她已经成了很普通的社会女生模样，没有了以前那种让我记得很深的书香气和礼貌感，打扮得成熟、性感，也很女性。当时我嘴上只是轻轻感叹一句“女大十八变”，现在想来，那里面其实藏着一种很深的失落。不是她现在这样有什么不好，而是我曾经在她身上见过一道很具体的美好，可后来，那道美好没有被世界珍惜，也没有被继续托住，最后只剩我还记得。读到这里，我才更懂“举善荐贤”为什么难：难的不只是认出谁好，而是你认出来之后，敢不敢承认，愿不愿意靠近，舍不舍得把它真正举出来。</p><p>再把“举善荐贤，饶人责己”连起来看时，我会觉得这一句一外一内，正好互相成全。前面的“举善荐贤”把眼光往外推，是在问：看见真的好，愿不愿意把它举出来；看见真正值得被托付的人，愿不愿意把他荐上去。可现实里，这件事并不容易。不是我们完全认不出善，而是很多时候，即便认出来了，也未必敢承认，未必愿意靠近，更未必舍得把它真正推出来。至于后面的“饶人责己”，则又把眼光收了回来。对我来说，“饶”并不轻，它不是嘴上说一句“算了”，也不是糊里糊涂地放过一切。它更像是在自己本来可以继续追、继续论、继续计较的时候，愿不愿意先收一点手，给别人留一点余地。所以“饶人”真正难的地方，不在不知道它好，而在自己受了气、受了委屈、甚至明明占着理的时候，还能不能不把人逼到底。可若一路读下来，我也会慢慢感觉到：饶别人，最后往往也是饶自己。因为若一直不肯饶，最先被困住的，常常不是别人，而是自己那颗不肯松下来的心。至于“责己”，我现在更愿意把它理解成“自照”。不是先责备自己，也不是给自己施压，而是把眼光先收回来，像拿一盏灯先照照自己，看看自己有没有偏、有没有急、有没有在占着理时就忘了分寸。这样，“责己”就不再是沉重的自责，而更像一种清醒：不急着判自己，也不急着替自己开脱，先把自己看明白一点。这样再看这八个字，它就不是软弱，也不是自我压迫，而是一种很难的平衡：对好的东西，肯推一把；对别人，不逼尽；对自己，不糊弄；最后都归回这颗心怎么安放。</p><p>读到“措衣食，周道路之饥寒；施棺椁，免尸骸之暴露”时，我会觉得这句把善一下拉到了最实处。前半句里的“措”字很有意思，它不像单纯的“给”，也不像居高临下的“赐”，而更像设法拿出来、安排出来、真正从自己手边拨一点出来。这样一来，这句就不只是有心，而是有行。看见别人难，心里动一下并不算太难；可真到了缺衣少食的时候，愿不愿意从自己这里拿一点出来，才是真正见分寸的地方。至于“衣食”，又写得很朴素，不是什么高远之事，而是人最基本的生存：穿得上，吃得下，能先把命和日子接住。读到“周道路之饥寒”时，我也会想到父母以前说过，上世纪六十年代很多时候饭都吃不饱，有饭大家都是抢着吃。这样一想，“衣食”就不是轻飘飘的词，而是活命的东西。若真把自己放在那种处境里，我也未必能做到无差别地周济陌生人。也许只能先顾父母、伴侣、孩子、身边最亲近的人；等自己吃饱一点、有余一点，才可能再往外分一点。这样说并不光彩，却很真实。也正因如此，这句才显得难。它不是要求人在自己也快撑不住时，还硬装成圣人，而是在问：当你还有一点余力时，愿不愿意把这点余力往外扩一点，不只停在自己和亲近的人身上，也能看见道路上那些正在饥寒里的人。现在再看“周”字，我更愿意把它理解成“把关照的圈子往外扩”。当然，它有周济之意，是让缺衣少食的人得到一点实际接济；但放在“道路之饥寒”里，它又不只是帮身边的人，而是把眼光投向那些路上、陌生、与自己未必有直接关系的人。人有亲疏，这不必假装没有。真正困难的是，当自己还有一点余力时，能不能让善不只停在父母妻儿、亲近之人那里，而是再往外多走一步。</p><p>后半句“施棺椁，免尸骸之暴露”则让整句的气一下沉了下来。前面的“衣食”还在讲活人最基本的生存，到这里已经到了人的最后一程。“暴露”这个词很重，它不只是尸体露在外面，而像是人死之后，连最后的遮蔽、安放和体面都没有了。所以“施棺椁”也不只是给一副葬具，而是在说：人活着时，要顾其饥寒；人死之后，也不让他彻底暴露无依。读到这里，我最先抓住的其实是那份“不忍”。因为若没有不忍，“施棺椁”就容易只剩一种礼俗；可有了这份不忍，它就变成了很深的善。尸骸已经不能回应你，也不能感谢你，甚至不再和你发生任何现实交换。可正因为如此，还愿意让他免于暴露，愿意给他最后一点遮蔽与安放，才显得格外肃穆。这里的不忍，不是为了回报，也不是为了被看见，而是不忍一个人死后仍无所归，不忍他连最后的体面都失去。这样再看，这句是在说：真正把人当人，不只是在他活着、能说话、能回报的时候，也包括在他已经无法回应你时，仍愿意承认他的尊严。而“棺椁”表面是在给死者最后的安放，可更深处，照见的也是活人的心与活人的体面。因为一个人死后是否还能被当作人来对待，不只是关乎死者，也关乎活着的人愿不愿意承认：生命哪怕走到尽头，仍不该被随便丢弃。这样一来，棺椁就不只是一副葬具，而像是人世间最后替“人”留住的一点体面。</p><p>再读“造漏泽之仁园，兴启蒙之义塾”时，我会觉得这一句很厚，也很远。它不像临时遇事搭把手，而是在说：能不能把善真正做成一个地方、一个入口、一个可以长期承接人的东西。前半句“造漏泽之仁园”，像是把前面“施棺椁”的那份不忍继续往前推了一步。若说“施棺椁”更像在具体的人身上，给死者最后一点遮蔽与安放，那么“造漏泽之仁园”就已经不只是应一时一事，而是在为那些无主、无依、无葬的人，造一个可以长期承接他们的地方。这里最有力量的，是“造”字。它不是临时碰见了帮一下，而是真愿意去建、去留、去让这样一个地方存在下来。至于“仁园”也很有意味。它不是冷冰冰的墓地之名，而是在提醒：即便一个人已经死了，也不该被世界彻底抛下。对我来说，这里的“仁”更像一种很具体的人道感：让人最后还有个归处。若只说仁心，容易还停在心里；可这里的“仁”已经落成了一个地方，一个能承接无主、无依、无葬者的地方。这样再看，这句想保住的就不只是尸骨的去处，而是一个社会在生命尽头处，仍愿意替“人”留住的一点归处与体面。</p><p>后半句“兴启蒙之义塾”则忽然从终点转向起点。前者是给无归者最后的归处，后者是给后来者看见世界的入口。这里的“兴”字和前面的“造”正好呼应：不是一时帮一下，而是把一件有益于人的事真正办起来、兴起来，让它能持续发生。若只是教一个孩子，那是一时一人；可“兴义塾”就不只是个人的帮助，而是在造一个能让更多人进入、受教、开明的场。对我来说，启蒙也不只是教知识，而更像“让人看见世界”。让一个原本只活在眼前、只困在自己那点经验里的人，开始知道原来世界还可以更大，原来人还可以这样想、这样看、这样活。至于“义塾”里的“义”，我更愿意把它理解成“不是为利，而是为人”。若办学只是为了利，那它就会变成交易：谁付得起，谁得到机会；谁没资源，谁就继续被挡在门外。可“义塾”不一样，它的根不在利，而在义。因为有人需要被教，因为孩子需要有机会看见世界，因为蒙着的人不该永远蒙着，所以愿意办这样一个地方。我会想到那些真心愿意去支教的人。若真是不为名利，愿意到艰苦处，把知识、眼界与陪伴带给原本缺少机会的人，那里面就有这个“义”字。这样再看整句，它就不只是两个古代名物，而像是在说：善到深处，不只是一次帮忙，而是替无归者留归处，替后来者开门路。</p><p>读到“家富，提携亲戚；岁饥，赈济邻朋”时，我会觉得这一句很有次第，也很有人间气。前半句“家富，提携亲戚”，问的并不只是一个人有没有钱，而是当一个人或一个家庭慢慢有了余力、有了资源、有了更好的位置之后，心会不会随之变掉。对我来说，这句更像是在问：人发达时，还记不记得来时的路，还想不想得到那些本来就和自己有牵连的人。这里最有味道的是“提携”二字。它不像单纯施舍，也不只是给一点好处，而更像往上提一提、往前带一带、在别人还没站稳时扶一扶。所以它说的并不是炫耀式的施恩，而是在提醒：若真的有余力，不要急着把自己从来路里切干净，也别只剩自己好，而是能不能把那一点好，带着身边人一起往前走一点。至于“亲戚”，我第一感觉还是会先落在血缘亲属这一层，这很自然，也最稳。这里当然不是说凡是有血缘关系的人，就都该无原则地照顾，更不是把“提携亲戚”读成帮亲不帮理。对我来说，它更像是在提醒：当一个人有了余力时，不要先把那些与自己本来就有来处关联的人忘掉。亲戚在这里，不只是一个关系称呼，也是在说：你若真走得更远一点、站得更稳一点，能不能还记得那些本就和你有牵连的人，而不是一富起来，就把来路也一并切掉。</p><p>后半句“岁饥，赈济邻朋”则让整句的分量一下更重了。它不是某个人一时的难，而更像整个年景不好，很多人都一起落进艰难里。这样一来，这句的重量就和“家富”那边完全不同了。家里富足时提携亲戚，毕竟还是在自己有余力的时候讲人情；可到了“岁饥”，就不是一个人、一家人的问题，而是整个环境都紧了，人人都可能先顾自己。想到父母那辈讲上世纪六十年代很多时候饭都吃不饱，有饭大家都是抢着吃，这两个字就更不轻了。它不是书上的词，而是真正会让人慌、让人缩、让人先顾自己命的处境。也正因如此，若在那样的时候还愿意赈济别人，这个“义”就更重了。对我来说，读到“赈济”时，更有感的不是单向的救济，而是群体性困境中的互助。因为放在“岁饥”下面，它说的就不只是某一个富人去帮某一个穷人，而更像是在年景不好、大家都一起艰难的时候，人和人之间还能不能互相托一把。这样再看，“赈济”就不只是慈善，而更像一种共度时艰的伦理：不是因为我高高在上，所以施给你；而是因为大家都在难里，却还不愿彼此彻底掉下去。至于“邻朋”，我第一感觉也还是落在邻居、朋友这一层。这很直，也最贴这句的现实感。它不是讲很远的人，也不是只讲家里人，而是讲那些和自己生活真的接着的人：平时会打照面的人，会来往的人，出了事彼此也能最先知道的人。这样再看，“邻朋”就很有分寸。它既没有把善推到过远的地方，变成一句空大的话；也没有只收在家门之内，变成只顾自己人。它刚好落在那一圈最日常、也最真实的人情网络里。尤其到了“岁饥”的时候，最能彼此照见、彼此托住的，往往也正是这些邻里朋友。这样再看整句，它就像是在说：人有余力时，不要忘了来路与亲缘；人共艰时，也不要失掉对周边之人的守望。</p><h2 id="【解读层】当前停靠点" tabindex="-1">【解读层】当前停靠点 <a class="header-anchor" href="#【解读层】当前停靠点" aria-label="Permalink to &quot;【解读层】当前停靠点&quot;">​</a></h2><p>后续建议从这句继续：</p><ul><li><code>依本分而致谦恭，守规矩而遵法度。</code></li></ul><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《文昌帝君阴骘文》</li><li><a href="https://zh.wikisource.org/zh-hans/%E6%96%87%E6%98%8C%E5%B8%9D%E5%90%9B%E9%99%B0%E9%A8%AD%E6%96%87" target="_blank" rel="noreferrer">维基文库：文昌帝君阴骘文（简体）</a></li><li>《汉书·于定国传》相关典故</li><li>窦禹钧“五子登科”相关民间流传典故</li></ul>',79)])])}const m=a(o,[["render",d]]);export{u as __pageData,m as default};
